import{_ as a,o as t,c as o,S as r}from"./chunks/framework.058ce8a4.js";const f=JSON.parse('{"title":"JSON API","description":"","frontmatter":{},"headers":[],"relativePath":"guide/json-api.md","lastUpdated":1778664862000}'),i={name:"guide/json-api.md"};function s(n,e,p,l,d,h){return t(),o("div",null,e[0]||(e[0]=[r('<h1 id="json-api" tabindex="-1">JSON API <a class="header-anchor" href="#json-api" aria-label="Permalink to &quot;JSON API&quot;">​</a></h1><p>The ExpoFP JSON API is a REST API that lets you programmatically manage your event floor plans and exhibitor data. Use it to integrate ExpoFP with your existing event management platform, CRM, or registration system — keeping booth assignments, exhibitor profiles, and floor plan data in sync without manual imports.</p><h2 id="what-you-can-do-with-the-api" tabindex="-1">What you can do with the API <a class="header-anchor" href="#what-you-can-do-with-the-api" aria-label="Permalink to &quot;What you can do with the API&quot;">​</a></h2><ul><li><strong>Manage exhibitors</strong> — create, update, and delete exhibitor profiles including company details, logos, descriptions, and contact information.</li><li><strong>Assign booths</strong> — add or remove booth assignments for exhibitors, mark booths as reserved or sold.</li><li><strong>Manage extras</strong> — assign sponsorship packages, booth extras, and featured listings to exhibitors.</li><li><strong>Read floor plan data</strong> — retrieve information about booths, exhibitors, and categories on your floor plan.</li></ul><p>Authentication is handled via an API key passed with each request. Get your key from <a href="https://app.expofp.com/profile/" target="_blank" rel="noreferrer">your ExpoFP profile page</a>.</p><p><strong>Base URL:</strong> <code>https://app.expofp.com</code></p><p>The full interactive reference — with request/response examples for every endpoint — is available at <a href="https://expofp.docs.apiary.io" target="_blank" rel="noreferrer">expofp.docs.apiary.io</a>.</p>',7)]))}const g=a(i,[["render",s]]);export{f as __pageData,g as default};
